PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?year
WHERE {
  ?person wdt:P1992 wd:Q3134293;
           wdt:P1992 wd:Q859497.
  ?ma_edition wdt:P2893 ?person;
               wdt:P585 ?date.
  BIND(YEAR(?date) AS ?year)
}
ORDER BY DESC(?year)
LIMIT 1
